using Microsoft.AspNetCore.Http;
using System.Net.Http;
using System.Threading.Tasks;

public class WebhookProxyController : ControllerBase
{
    private readonly IHttpClientFactory _httpClientFactory;

    public WebhookProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [HttpPost("/proxy")]
    public async Task<IActionResult> ForwardRequest(HttpRequest request)
    {
        string targetUrl = request.Query["targetUrl"].ToString();

        using var httpClient = _httpClientFactory.CreateClient();
        HttpResponseMessage response = await httpClient.GetAsync(targetUrl);

        return new ContentResult
        {
            Content = await response.Content.ReadAsStringAsync(),
            StatusCode = (int)response.StatusCode,
        };
    }
}